const items = $input.all();
const messages = items.map(item => {
  const r = item.json;
  const statusEmoji = r.status === 'hit_target' ? '\u2705' : r.status === 'hit_stop' ? '\u274c' : '\u23f0';
  const dirEmoji = r.direction === 'long' ? '\ud83d\udfe2' : '\ud83d\udd34';
  const pnl = r.pnl_pct >= 0 ? `+${r.pnl_pct}%` : `${r.pnl_pct}%`;

  return {
    json: {
      message: `${statusEmoji} *Signal closed:* ${dirEmoji} ${r.asset} ${r.direction.toUpperCase()}\n\nEntry: ${r.entry_price} > Exit: ${r.exit_price}\nTarget: ${r.target_price} | Stop: ${r.stop_price}\n\n*Result:* ${pnl} | R: ${r.r_multiple}\n*Status:* ${r.status.replace('_', ' ')}`
    }
  };
});
return messages;

